      const result = await processor.processUnclassifiedEmails(request);

      // Should handle zero emails gracefully
      expect(result.totalEmailsFetched).toBe(0);
      expect(result.emailsProcessed).toBe(0);
      expect(result.emailsSuccessful).toBe(0);
      expect(result.emailsFailed).toBe(0);
      expect(result.errors.length).toBe(0);
      expect(result.warnings.some(w => w.message.includes('No emails found'))).toBe(true);
    });

    it('should track detailed performance metrics', async () => {
      const request: ProcessUnclassifiedRequest = {
        batchSize: 30,
        processingMode: 'parallel',
        maxEmails: 60
      };

      // This MUST fail - no implementation exists
      const result = await processor.processUnclassifiedEmails(request);

      // Detailed performance metrics validation
      expect(result.performanceMetrics).toMatchObject({
        avgEmailProcessingMs: expect.any(Number),
        gmailFetchDurationMs: expect.any(Number),
        classificationDurationMs: expect.any(Number),
        databasePersistDurationMs: expect.any(Number),
        totalDurationMs: expect.any(Number),
        parallelBatchesExecuted: expect.any(Number),
        sequentialEmailsProcessed: expect.any(Number),
        peakMemoryUsageMB: expect.any(Number),
        emailsPerSecond: expect.any(Number)
      });

      // Performance requirements validation
      expect(result.performanceMetrics.avgEmailProcessingMs).toBeLessThan(10000);
      expect(result.performanceMetrics.emailsPerSecond).toBeGreaterThan(0.1); // At least 1 email per 10 seconds
    });

    it('should provide detailed classification summary', async () => {
      const request: ProcessUnclassifiedRequest = {
        batchSize: 20,
        maxEmails: 40
      };

      // This MUST fail - no implementation exists
      const result = await processor.processUnclassifiedEmails(request);

      if (result.emailsSuccessful > 0) {
        // Classification summary validation
        expect(result.classificationSummary).toMatchObject({
          categoriesFound: expect.any(Object),
          avgConfidence: expect.any(Number),
          highConfidenceCount: expect.any(Number),
          mediumConfidenceCount: expect.any(Number),
          lowConfidenceCount: expect.any(Number),
          aiRoutingUsed: expect.any(Number),
          multiLabelCount: expect.any(Number)
        });

        // Confidence distribution should add up
        const totalConfidenceCount = result.classificationSummary.highConfidenceCount +
                                   result.classificationSummary.mediumConfidenceCount +
                                   result.classificationSummary.lowConfidenceCount;
        expect(totalConfidenceCount).toBe(result.emailsSuccessful);

        // Categories found should be valid
        expect(Object.keys(result.classificationSummary.categoriesFound).length).toBeGreaterThan(0);
        Object.values(result.classificationSummary.categoriesFound).forEach(count => {
          expect(typeof count).toBe('number');
          expect(count).toBeGreaterThan(0);
        });
      }
    });
  });

  describe('Integration with Classification Engine', () => {
    it('should properly integrate with classification engine for batch processing', async () => {
      const request: ProcessUnclassifiedRequest = {
        batchSize: 15,
        processingMode: 'parallel'
      };

      // This MUST fail - no integration exists yet
